function SocialIcon({ label, children }: { label: string; children: React.ReactNode }) {
	return (
		<a
			href="/"
			aria-label={label}
			className="flex items-center justify-center w-[1.25em] h-[1.25em] text-opal hover:text-ecru-white transition-colors"
		>
			<span className="sr-only">{label}</span>
			{children}
		</a>
	)
}
